class TestAuthentication:

    def test_unauthenticated_user_cannot_update(
        self, ui_form_handler, unauthenticated_user, valid_form_data
    ):
        """Un-authenticated requests must be rejected with HTTP 401."""
        result = _handle(ui_form_handler, unauthenticated_user, 42, valid_form_data)

        assert result.status == 401
        assert any("authentication" in e.lower() for e in result.errors)

    def test_unauthenticated_user_gets_no_data(
        self, ui_form_handler, unauthenticated_user, valid_form_data
    ):
        result = _handle(ui_form_handler, unauthenticated_user, 42, valid_form_data)
        assert result.data is None

    def test_unauthenticated_user_does_not_call_service(
        self, ui_form_handler, unauthenticated_user, valid_form_data, announcement_service
    ):
        _handle(ui_form_handler, unauthenticated_user, 42, valid_form_data)
        announcement_service.update.assert_not_called()

    def test_unauthenticated_user_does_not_write_audit(
        self, ui_form_handler, unauthenticated_user, valid_form_data, audit_service
    ):
        _handle(ui_form_handler, unauthenticated_user, 42, valid_form_data)
        audit_service.write.assert_not_called()


