class TestEdgeCases:

    def test_optional_fields_are_accepted(
        self, ui_form_handler, system_admin_user, valid_form_data
    ):
        """Extra optional fields in the payload must not break the update."""
        form_data = {**valid_form_data, "pinned_until": "2099-12-31", "priority": "high"}
        result = _handle(ui_form_handler, system_admin_user, 42, form_data)
        assert result.status == 200

    def test_update_with_is_active_false_succeeds(
        self, ui_form_handler, system_admin_user, valid_form_data
    ):
        """Deactivating an announcement is a valid update."""
        form_data = {**valid_form_data, "is_active": False}
        result = _handle(ui_form_handler, system_admin_user, 42, form_data)
        assert result.status == 200

    def test_title_with_only_whitespace_is_invalid(
        self, ui_form_handler, system_admin_user, valid_form_data
    ):
        form_data = {**valid_form_data, "title": "     "}
        result = _handle(ui_form_handler, system_admin_user, 42, form_data)
        assert result.status == 422

    def test_very_long_title_reaches_service(
        self, ui_form_handler, system_admin_user, valid_form_data, announcement_service
    ):
        """Field-length enforcement is the service's responsibility; the form
        handler must pass the value through and not silently truncate it."""
        form_data = {**valid_form_data, "title": "A" * 1000}
        _handle(ui_form_handler, system_admin_user, 42, form_data)
        call_args = announcement_service.update.call_args
        assert call_args.args[1]["title"] == "A" * 1000

    def test_service_exception_propagates_without_audit(
        self, ui_form_handler, system_admin_user, valid_form_data,
        announcement_service, audit_service
    ):
        """If the persistence layer raises, no audit record should be written."""
        announcement_service.update.side_effect = RuntimeError("DB connection lost")

        with pytest.raises(RuntimeError, match="DB connection lost"):
            _handle(ui_form_handler, system_admin_user, 42, valid_form_data)

        audit_service.write.assert_not_called()

    def test_result_data_is_none_on_validation_failure(
        self, ui_form_handler, system_admin_user
    ):
        result = _handle(ui_form_handler, system_admin_user, 42, {})
        assert result.data is None
